/**
 * Devuelve las entradas fijas para el idioma indicado.
 * Si el idioma no tiene entradas propias, usa 'es' como fallback.
 *
 * @param {string} lang - Código de idioma: es, en, pt, fr, de, it
 * @returns {Array} Array de entradas con el prefijo de ID 'lcp-bot-'
 */
function getFixedEntries(lang) {
  const langEntries = FIXED_ENTRIES[lang] || FIXED_ENTRIES['es'];
  // Normaliza IDs y deduplica (primera ocurrencia gana — la más detallada)
  const seen = new Set();
  return langEntries
    .map(entry => ({
      ...entry,
      id: entry.id.startsWith('lcp-') ? entry.id : `lcp-bot-${entry.id}`,
    }))
    .filter(entry => {
      if (seen.has(entry.id)) return false;
      seen.add(entry.id);
      return true;
    });
}

